(window.webpackJsonp=window.webpackJsonp||[]).push([[305],{587:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * @param {string[]} words\\n * @param {string[]} puzzles\\n * @return {number[]}\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findNumOfValidWords = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">words, puzzles</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> cp=[]\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">compress</span>(<span class=\\"hljs-params\\">words</span>)</span>{\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> s <span class=\\"hljs-keyword\\">of</span> words){\\n      <span class=\\"hljs-keyword\\">let</span> bit=<span class=\\"hljs-number\\">0</span>\\n      <span class=\\"hljs-keyword\\">let</span> <span class=\\"hljs-keyword\\">set</span>=new Set()\\n      // \u6784\u5efawords\u96c6\u5408\u538b\u7f29\\n      for(let i=0;i&lt;s.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> code=s.charCodeAt(i)<span class=\\"hljs-number\\">-97</span>\\n        <span class=\\"hljs-keyword\\">set</span>.add(code)\\n        bit=bit | (1&lt;&lt;code)\\n      }\\n      if(<span class=\\"hljs-keyword\\">set</span>.size&gt;7)continue\\n      cp.push(bit)\\n    }\\n  }\\n  compress(words)\\n  let res=Array(puzzles.length).fill(0)\\n  for(let i=0;i&lt;puzzles.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> bit=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-comment\\">// \u6784\u5efapuzzles\u96c6\u5408\u538b\u7f29</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;puzzles[i].length;j++){\\n      <span class=\\"hljs-keyword\\">let</span> code=puzzles[i].charCodeAt(j)<span class=\\"hljs-number\\">-97</span>\\n      bit=bit|(<span class=\\"hljs-number\\">1</span>&lt;&lt;code)\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> num=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> firstBit=<span class=\\"hljs-number\\">1</span>&lt;&lt;(puzzles[i].charCodeAt(<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-number\\">-97</span>)\\n    <span class=\\"hljs-comment\\">// \u6bd4\u8f83\u96c6\u5408\u538b\u7f29</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;cp.length;j++){\\n      <span class=\\"hljs-keyword\\">if</span>(((cp[j] &amp; bit)===cp[j]) &amp;&amp; ((firstBit &amp; cp[j])===firstBit)){\\n        num++\\n      }\\n    }\\n    res[i]=num\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"number-of-valid-words-for-each-puzzle","hasThinking":false,"content":"<p>\u5916\u56fd\u53cb\u4eba\u4eff\u7167\u4e2d\u56fd\u5b57\u8c1c\u8bbe\u8ba1\u4e86\u4e00\u4e2a\u82f1\u6587\u7248\u731c\u5b57\u8c1c\u5c0f\u6e38\u620f\uff0c\u8bf7\u4f60\u6765\u731c\u731c\u770b\u5427\u3002</p>\\n\\n<p>\u5b57\u8c1c\u7684\u8ff7\u9762&nbsp;<code>puzzle</code> \u6309\u5b57\u7b26\u4e32\u5f62\u5f0f\u7ed9\u51fa\uff0c\u5982\u679c\u4e00\u4e2a\u5355\u8bcd&nbsp;<code>word</code>&nbsp;\u7b26\u5408\u4e0b\u9762\u4e24\u4e2a\u6761\u4ef6\uff0c\u90a3\u4e48\u5b83\u5c31\u53ef\u4ee5\u7b97\u4f5c\u8c1c\u5e95\uff1a</p>\\n\\n<ul>\\n\\t<li>\u5355\u8bcd&nbsp;<code>word</code>&nbsp;\u4e2d\u5305\u542b\u8c1c\u9762&nbsp;<code>puzzle</code>&nbsp;\u7684\u7b2c\u4e00\u4e2a\u5b57\u6bcd\u3002</li>\\n\\t<li>\u5355\u8bcd&nbsp;<code>word</code>&nbsp;\u4e2d\u7684\u6bcf\u4e00\u4e2a\u5b57\u6bcd\u90fd\u53ef\u4ee5\u5728\u8c1c\u9762&nbsp;<code>puzzle</code>&nbsp;\u4e2d\u627e\u5230\u3002<br>\\n\\t\u4f8b\u5982\uff0c\u5982\u679c\u5b57\u8c1c\u7684\u8c1c\u9762\u662f &quot;abcdefg&quot;\uff0c\u90a3\u4e48\u53ef\u4ee5\u4f5c\u4e3a\u8c1c\u5e95\u7684\u5355\u8bcd\u6709 &quot;faced&quot;, &quot;cabbage&quot;, \u548c &quot;baggage&quot;\uff1b\u800c &quot;beefed&quot;\uff08\u4e0d\u542b\u5b57\u6bcd &quot;a&quot;\uff09\u4ee5\u53ca&nbsp;&quot;based&quot;\uff08\u5176\u4e2d\u7684 &quot;s&quot; \u6ca1\u6709\u51fa\u73b0\u5728\u8c1c\u9762\u4e2d\uff09\u3002</li>\\n</ul>\\n\\n<p>\u8fd4\u56de\u4e00\u4e2a\u7b54\u6848\u6570\u7ec4&nbsp;<code>answer</code>\uff0c\u6570\u7ec4\u4e2d\u7684\u6bcf\u4e2a\u5143\u7d20&nbsp;<code>answer[i]</code>&nbsp;\u662f\u5728\u7ed9\u51fa\u7684\u5355\u8bcd\u5217\u8868 <code>words</code> \u4e2d\u53ef\u4ee5\u4f5c\u4e3a\u5b57\u8c1c\u8ff7\u9762&nbsp;<code>puzzles[i]</code>&nbsp;\u6240\u5bf9\u5e94\u7684\u8c1c\u5e95\u7684\u5355\u8bcd\u6570\u76ee\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>\\nwords = [&quot;aaaa&quot;,&quot;asas&quot;,&quot;able&quot;,&quot;ability&quot;,&quot;actt&quot;,&quot;actor&quot;,&quot;access&quot;], \\npuzzles = [&quot;aboveyz&quot;,&quot;abrodyz&quot;,&quot;abslute&quot;,&quot;absoryz&quot;,&quot;actresz&quot;,&quot;gaswxyz&quot;]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,1,3,2,4,0]\\n<strong>\u89e3\u91ca\uff1a</strong>\\n1 \u4e2a\u5355\u8bcd\u53ef\u4ee5\u4f5c\u4e3a &quot;aboveyz&quot; \u7684\u8c1c\u5e95 : &quot;aaaa&quot; \\n1 \u4e2a\u5355\u8bcd\u53ef\u4ee5\u4f5c\u4e3a &quot;abrodyz&quot; \u7684\u8c1c\u5e95 : &quot;aaaa&quot;\\n3 \u4e2a\u5355\u8bcd\u53ef\u4ee5\u4f5c\u4e3a &quot;abslute&quot; \u7684\u8c1c\u5e95 : &quot;aaaa&quot;, &quot;asas&quot;, &quot;able&quot;\\n2 \u4e2a\u5355\u8bcd\u53ef\u4ee5\u4f5c\u4e3a&nbsp;&quot;absoryz&quot; \u7684\u8c1c\u5e95 : &quot;aaaa&quot;, &quot;asas&quot;\\n4 \u4e2a\u5355\u8bcd\u53ef\u4ee5\u4f5c\u4e3a&nbsp;&quot;actresz&quot; \u7684\u8c1c\u5e95 : &quot;aaaa&quot;, &quot;asas&quot;, &quot;actt&quot;, &quot;access&quot;\\n\u6ca1\u6709\u5355\u8bcd\u53ef\u4ee5\u4f5c\u4e3a&nbsp;&quot;gaswxyz&quot; \u7684\u8c1c\u5e95\uff0c\u56e0\u4e3a\u5217\u8868\u4e2d\u7684\u5355\u8bcd\u90fd\u4e0d\u542b\u5b57\u6bcd &#39;g&#39;\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= words.length &lt;= 10^5</code></li>\\n\\t<li><code>4 &lt;= words[i].length &lt;= 50</code></li>\\n\\t<li><code>1 &lt;= puzzles.length &lt;= 10^4</code></li>\\n\\t<li><code>puzzles[i].length == 7</code></li>\\n\\t<li><code>words[i][j]</code>, <code>puzzles[i][j]</code>&nbsp;\u90fd\u662f\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u3002</li>\\n\\t<li>\u6bcf\u4e2a&nbsp;<code>puzzles[i]</code>&nbsp;\u6240\u5305\u542b\u7684\u5b57\u7b26\u90fd\u4e0d\u91cd\u590d\u3002</li>\\n</ul>\\n"}')}}]);